import{_ as r}from"./Menu.b66ac8de.js";import{u as s}from"./composables.7a114ca2.js";import{r as e,a as n,e as u,b as l,f as i,o as c}from"./entry.04c0a871.js";const d={class:"banniere"},p=i('<div class="margium-l"><div class="espacium"><h1>KoGame</h1><div class="colonnes"><div class="colonne"><div class="projettitre">Contexte</div> Projet D&#39;\xE9tude \xE0 l&#39;\xE9tranger - DUT MMI </div><div class="colonne"><div class="projettitre">Distinction</div> Premier prix d\xE9veloppement web de l\u2019IDMSC de l\u2019Universit\xE9 Politehnica Timi\u0219oara </div><div class="colonne"><div class="projettitre">P\xE9riode</div> Mai 2019 - 1 semaine </div><div class="colonne"><a href="https://kogame.lucaslacroix.com" class="lienapp" target="_blank">Jouer \xE0 KoGame</a></div></div></div></div>',1),v=i('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p>Projet de jeu javascript con\xE7u, test\xE9 et d\xE9velopp\xE9 en une semaine pour le concours <i>Interactive Digital Media Student Contest 2019</i> de l&#39;Universit\xE9 Politehnica Timi\u0219oara.</p><h2>Le concept du jeu</h2><p> Notre joueur se d\xE9place sur une grille, il doit \xE9viter les 2 robots qui le poursuive. Pour gagner (Dans le mode normal) il doit collecter 10 points et attraper le robot jaune. </p><h2>Le retours des tests utilisateur</h2><p> Les test utilisateurs on relev\xE9 plusieurs difficult\xE9s : <ul><li> Le jeu n&#39;\xE9tait pas toujours adapt\xE9 au niveau des utilisateur, pour certains, cela \xE9tait trop facile et d&#39;autre trop compliquer pour gagner. <br>\u2192 J&#39;ai ajout\xE9 un choix de niveau de difficult\xE9 avant d\u2019acc\xE9der au jeux, le choix ser r\xE9percute sur le nombre de point a accumuler pour gagner et la rapidit\xE9 des robots. </li><li> Le moyen de gagner et le concept de jeux n&#39;est pas toujours compris <br>\u2192Ajout d&#39;une banni\xE8re explicative \xE0 l&#39;entr\xE9 du jeu. </li><li> Certains utilisateur on souhaiter l&#39;utiliser sur mobile. La version test\xE9 fonctionnais exclusivement au clavier.<br> \u2192 cr\xE9ation de touche pour l&#39;utilisation mobile du jeu. </li><li> Bogues techniques<br> \u2192 Corrections des bogues survenu sur certain navigateur ou certain cas de figure du jeu. </li></ul></p></div></div></article>',1),f={__name:"kogame",setup(m){const t=e("KoGame - Lucas Lacroix"),a=e("Projet de jeu javascript con\xE7u, test\xE9 et d\xE9velopp\xE9 en une semaine pour le concours <i>Interactive Digital Media Student Contest 2019</i> de l'Universit\xE9 Politehnica Timi\u0219oara.");return s({title:t,meta:[{name:"description",content:a}]}),(g,j)=>{const o=r;return c(),n("div",null,[u("div",d,[l(o),p]),v])}}};export{f as default};
